(window.webpackJsonp=window.webpackJsonp||[]).push([[585],{854:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">arr</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">pieces</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{boolean}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> canFormArray = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">arr, pieces</span>) </span>{\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;pieces.length;i++){\\n        <span class=\\"hljs-keyword\\">if</span>(!isExist(pieces[i]))<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">false</span>\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-literal\\">true</span>\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">isExist</span>(<span class=\\"hljs-params\\">p</span>)</span>{\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;arr.length;i++){\\n            <span class=\\"hljs-keyword\\">if</span>(arr[i]===p[<span class=\\"hljs-number\\">0</span>]){\\n                <span class=\\"hljs-keyword\\">return</span> arr.slice(i,i+p.length).toString()===p.toString()\\n            }\\n        }\\n    }\\n};\\n</code></pre>\\n"],"titleSlug":"check-array-formation-through-concatenation","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4 <code>arr</code> \uff0c\u6570\u7ec4\u4e2d\u7684\u6bcf\u4e2a\u6574\u6570 <strong>\u4e92\u4e0d\u76f8\u540c</strong> \u3002\u53e6\u6709\u4e00\u4e2a\u7531\u6574\u6570\u6570\u7ec4\u6784\u6210\u7684\u6570\u7ec4 <code>pieces</code>\uff0c\u5176\u4e2d\u7684\u6574\u6570\u4e5f <strong>\u4e92\u4e0d\u76f8\u540c</strong> \u3002\u8bf7\u4f60\u4ee5 <strong>\u4efb\u610f\u987a\u5e8f</strong> \u8fde\u63a5 <code>pieces</code> \u4e2d\u7684\u6570\u7ec4\u4ee5\u5f62\u6210 <code>arr</code> \u3002\u4f46\u662f\uff0c<strong>\u4e0d\u5141\u8bb8</strong> \u5bf9\u6bcf\u4e2a\u6570\u7ec4 <code>pieces[i]</code> \u4e2d\u7684\u6574\u6570\u91cd\u65b0\u6392\u5e8f\u3002</p>\\n\\n<p>\u5982\u679c\u53ef\u4ee5\u8fde\u63a5<em> </em><code>pieces</code> \u4e2d\u7684\u6570\u7ec4\u5f62\u6210 <code>arr</code> \uff0c\u8fd4\u56de <code>true</code> \uff1b\u5426\u5219\uff0c\u8fd4\u56de <code>false</code> \u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>arr = [85], pieces = [[85]]\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>arr = [15,88], pieces = [[88],[15]]\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n<strong>\u89e3\u91ca\uff1a</strong>\u4f9d\u6b21\u8fde\u63a5 <code>[15]</code> \u548c <code>[88]</code>\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>arr = [49,18,16], pieces = [[16,18,49]]\\n<strong>\u8f93\u51fa\uff1a</strong>false\\n<strong>\u89e3\u91ca\uff1a</strong>\u5373\u4fbf\u6570\u5b57\u76f8\u7b26\uff0c\u4e5f\u4e0d\u80fd\u91cd\u65b0\u6392\u5217 pieces[0]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>arr = [91,4,64,78], pieces = [[78],[4,64],[91]]\\n<strong>\u8f93\u51fa\uff1a</strong>true\\n<strong>\u89e3\u91ca\uff1a</strong>\u4f9d\u6b21\u8fde\u63a5 <code>[91]</code>\u3001<code>[4,64]</code> \u548c <code>[78]</code></pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>arr = [1,3,5,7], pieces = [[2,4,6,8]]\\n<strong>\u8f93\u51fa\uff1a</strong>false\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= pieces.length <= arr.length <= 100</code></li>\\n\\t<li><code>sum(pieces[i].length) == arr.length</code></li>\\n\\t<li><code>1 <= pieces[i].length <= arr.length</code></li>\\n\\t<li><code>1 <= arr[i], pieces[i][j] <= 100</code></li>\\n\\t<li><code>arr</code> \u4e2d\u7684\u6574\u6570 <strong>\u4e92\u4e0d\u76f8\u540c</strong></li>\\n\\t<li><code>pieces</code> \u4e2d\u7684\u6574\u6570 <strong>\u4e92\u4e0d\u76f8\u540c</strong>\uff08\u4e5f\u5c31\u662f\u8bf4\uff0c\u5982\u679c\u5c06 <code>pieces</code> \u6241\u5e73\u5316\u6210\u4e00\u7ef4\u6570\u7ec4\uff0c\u6570\u7ec4\u4e2d\u7684\u6240\u6709\u6574\u6570\u4e92\u4e0d\u76f8\u540c\uff09</li>\\n</ul>\\n","title":"1640. \u80fd\u5426\u8fde\u63a5\u5f62\u6210\u6570\u7ec4","relatedTags":["\u6392\u5e8f","\u6570\u7ec4","\u54c8\u5e0c\u8868"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1640"}')}}]);